  9	import SearchItem from '@kubevirt-utils/components/SearchItem/SearchItem';
 10	import VirtualMachineDescriptionItem from '@kubevirt-utils/components/VirtualMachineDescriptionItem/VirtualMachineDescriptionItem';
 11	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 12	import { getEvictionStrategy } from '@kubevirt-utils/resources/vm';
 13	import { isInstanceTypeVM } from '@kubevirt-utils/resources/vm/utils/instanceTypes';
 14	import { k8sUpdate } from '@openshift-console/dynamic-plugin-sdk';
 15	import { DescriptionList, GridItem } from '@patternfly/react-core';
 16	
 17	import DedicatedResources from './DedicatedResources';
 18	
 19	type SchedulingSectionRightGridProps = {
 20	  canUpdateVM: boolean;
 21	  instanceTypeVM?: V1VirtualMachine;
 22	  onUpdateVM?: (updatedVM: V1VirtualMachine) => Promise<V1VirtualMachine>;
 23	  vm: V1VirtualMachine;
 24	  vmi?: V1VirtualMachineInstance;
 25	};
 26	
 27	const SchedulingSectionRightGrid: FC<SchedulingSectionRightGridProps> = ({
 28	  canUpdateVM,
 29	  instanceTypeVM,
 30	  onUpdateVM,
 31	  vm,
 32	  vmi,
 33	}) => {
 34	  const { t } = useKubevirtTranslation();
 35	  const { createModal } = useModal();
 36	
 37	  const onSubmit = useCallback(
 38	    (updatedVM: V1VirtualMachine) =>
 39	      onUpdateVM
 40	        ? onUpdateVM(updatedVM)
 41	        : k8sUpdate({
 42	            data: updatedVM,
 43	            model: VirtualMachineModel,
 44	            name: updatedVM?.metadata?.name,
 45	            ns: updatedVM?.metadata?.namespace,
 46	          }),
 47	    [onUpdateVM],
 48	  );
 49	
 50	  return (
 51	    <GridItem span={5}>
 52	      <DescriptionList className="pf-v6-c-description-list">
 53	        <VirtualMachineDescriptionItem
 54	          descriptionHeader={
 55	            <SearchItem id="dedicated-resources">{t('Dedicated resources')}</SearchItem>
 56	          }
 57	          messageOnDisabled={t(
 58	            'Can not configure dedicated resources if the VirtualMachine is created from Instance Type',
 59	          )}
 60	          onEditClick={() =>
 61	            createModal(({ isOpen, onClose }) => (
 62	              <DedicatedResourcesModal
 63	                headerText={t('Dedicated resources')}
 64	                isOpen={isOpen}
 65	                onClose={onClose}
 66	                onSubmit={onSubmit}
 67	                vm={vm}
 68	                vmi={vmi}
 69	              />
 70	            ))
 71	          }
 72	          data-test-id="dedicated-resources"
 73	          descriptionData={<DedicatedResources vm={isInstanceTypeVM(vm) ? instanceTypeVM : vm} />}
 74	          isDisabled={isInstanceTypeVM(vm)}
 75	          isEdit={canUpdateVM}
 76	        />
 77	        <VirtualMachineDescriptionItem
 78	          descriptionHeader={
 79	            <SearchItem id="eviction-strategy">{t('Eviction strategy')}</SearchItem>
 80	          }
 81	          onEditClick={() =>
 82	            createModal(({ isOpen, onClose }) => (
 83	              <EvictionStrategyModal
 84	                headerText={t('Eviction strategy')}
 85	                isOpen={isOpen}
 86	                onClose={onClose}
 87	                onSubmit={onSubmit}
 88	                vm={vm}
 89	                vmi={vmi}
 90	              />
 91	            ))
 92	          }
 93	          data-test-id="eviction-strategy"
 94	          descriptionData={<ShowEvictionStrategy evictionStrategy={getEvictionStrategy(vm)} />}
 95	          isEdit={canUpdateVM}
 96	        />
 97	      </DescriptionList>
 98	    </GridItem>
 99	  );
100	};
101	
102	export default SchedulingSectionRightGrid;

